    {"question": "भगत सिंह कौन था?", "answer": "भगत सिंह महान क्रांतिकारी और देशभक्त था। उसने 1929 में असेंबली में बम फेंका और 23 मार्च 1931 को फाँसी पर चढ़ गया।"},
    {"question": "सुभाष चंद्र बोस कौन था?", "answer": "नेताजी सुभाष चंद्र बोस महान स्वतंत्रता सेनानी थे। उन्होंने 'आजाद हिंद फौज' बनाई और नारा दिया — 'तुम मुझे खून दो, मैं तुम्हें आजादी दूँगा।'"},
    {"question": "भारत कब स्वतंत्र हुआ?", "answer": "भारत 15 अगस्त 1947 को ब्रिटिश शासन से स्वतंत्र हुआ। पंडित जवाहरलाल नेहरू भारत के पहले प्रधानमंत्री बने।"},
    {"question": "भारत का संविधान कब लागू हुआ?", "answer": "भारत का संविधान 26 जनवरी 1950 को लागू हुआ। डॉ. भीमराव अंबेडकर संविधान सभा की मसौदा समिति के अध्यक्ष थे।"},
    {"question": "डॉ. अंबेडकर कौन थे?", "answer": "डॉ. भीमराव अंबेडकर भारतीय संविधान के शिल्पकार थे। वे दलित वर्ग के महान नेता, विधिवेत्ता और समाज सुधारक थे।"},
    {"question": "जवाहरलाल नेहरू कौन थे?", "answer": "जवाहरलाल नेहरू भारत के पहले प्रधानमंत्री थे जिन्होंने 1947 से 1964 तक शासन किया। वे आधुनिक भारत के निर्माता माने जाते हैं।"},
    {"question": "सरदार पटेल कौन थे?", "answer": "सरदार वल्लभभाई पटेल 'लौह पुरुष' कहलाते हैं। उन्होंने 562 रियासतों को मिलाकर अखंड भारत बनाया।"},
    {"question": "बंगाल विभाजन कब हुआ?", "answer": "बंगाल का पहला विभाजन 1905 में लॉर्ड कर्जन ने किया। इसके विरोध में स्वदेशी आंदोलन शुरू हुआ।"},
    {"question": "जलियाँवाला बाग हत्याकांड क्या था?", "answer": "13 अप्रैल 1919 को जनरल डायर के आदेश पर अमृतसर के जलियाँवाला बाग में निहत्थी भीड़ पर गोलियाँ चलाई गईं जिसमें सैकड़ों लोग मारे गए।"},
    {"question": "चौरी चौरा कांड क्या था?", "answer": "चौरी चौरा कांड 4 फरवरी 1922 को हुआ जब भीड़ ने एक पुलिस चौकी जला दी। इसके बाद गांधीजी ने असहयोग आंदोलन वापस ले लिया।"},
    {"question": "साइमन कमीशन क्या था?", "answer": "साइमन कमीशन 1927 में ब्रिटिश सरकार ने भेजा। इसमें कोई भारतीय सदस्य न होने से भारी विरोध हुआ और लाला लाजपत राय घायल हुए।"},
    {"question": "राम कौन थे?", "answer": "राम अयोध्या के राजा थे। वे विष्णु के सातवें अवतार माने जाते हैं और मर्यादा पुरुषोत्तम कहलाते हैं।"},
    {"question": "राम के पिता कौन थे?", "answer": "राम के पिता दशरथ थे, जो अयोध्या के महान राजा थे।"},
    {"question": "राम की माता कौन थीं?", "answer": "राम की माता कौशल्या थीं, जो दशरथ की पहली पत्नी थीं।"},
    {"question": "सीता कौन थीं?", "answer": "सीता राम की पत्नी थीं। वे जनक राजा की पुत्री थीं और धरती माता की बेटी मानी जाती हैं।"},
    {"question": "सीता के पिता कौन थे?", "answer": "सीता के पिता राजा जनक थे, जो मिथिला के राजा थे।"},
    {"question": "हनुमान कौन थे?", "answer": "हनुमान राम के परम भक्त और महान वानर योद्धा थे। वे शक्ति, भक्ति और बुद्धि के प्रतीक हैं।"},
    {"question": "हनुमान के पिता कौन थे?", "answer": "हनुमान के पिता वायु देव (पवन देव) थे, इसलिए उन्हें पवनपुत्र भी कहते हैं।"},
    {"question": "लक्ष्मण कौन थे?", "answer": "लक्ष्मण राम के छोटे भाई थे। वे सुमित्रा के पुत्र थे और राम के साथ वनवास गए थे।"},
    {"question": "भरत कौन थे?", "answer": "भरत राम के भाई थे और कैकेयी के पुत्र थे। उन्होंने राम की अनुपस्थिति में उनकी खड़ाऊँ रखकर राज्य संभाला।"},
    {"question": "शत्रुघ्न कौन थे?", "answer": "शत्रुघ्न राम के भाई थे और सुमित्रा के पुत्र थे।"},
    {"question": "रावण कौन था?", "answer": "रावण लंका का राक्षस राजा था। वह बहुत शक्तिशाली और विद्वान था, लेकिन उसने सीता का अपहरण किया।"},
    {"question": "रावण के कितने सिर थे?", "answer": "रावण के दस सिर थे, इसलिए उसे दशानन भी कहते हैं।"},
    {"question": "कुंभकरण कौन था?", "answer": "कुंभकरण रावण का भाई था। वह बहुत विशाल था और छह महीने सोता था।"},
    {"question": "मेघनाद कौन था?", "answer": "मेघनाद रावण का पुत्र था। उसे इंद्रजीत भी कहते थे क्योंकि उसने इंद्र को हराया था।"},
    {"question": "राम का जन्म कहाँ हुआ?", "answer": "राम का जन्म अयोध्या में हुआ। यह नगरी सरयू नदी के किनारे है।"},
    {"question": "राम वनवास क्यों गए?", "answer": "राम इसलिए वनवास गए क्योंकि उनकी सौतेली माँ कैकेयी ने राजा दशरथ से दो वरदान माँगे — एक में भरत को राजा बनाना और दूसरे में राम को 14 साल का वनवास।"},
    {"question": "सीता का हरण किसने किया?", "answer": "सीता का हरण रावण ने किया। उसने स्वर्ण मृग का रूप धारण करके राम को दूर किया और फिर सीता को लंका ले गया।"},
    {"question": "हनुमान ने लंका क्यों जलाई?", "answer": "जब रावण के सैनिकों ने हनुमान की पूँछ में आग लगाई, तब हनुमान ने उसी आग से पूरी लंका जला दी।"},
    {"question": "राम ने रावण को कैसे हराया?", "answer": "राम ने विभीषण की सहायता से रावण की नाभि में बाण मारकर उसे मारा। यह रहस्य विभीषण ने बताया था।"},
    {"question": "कृष्ण कौन थे?", "answer": "कृष्ण विष्णु के आठवें अवतार थे। वे योगेश्वर, नीतिज्ञ और प्रेम के प्रतीक हैं।"},
    {"question": "कृष्ण का जन्म कहाँ हुआ?", "answer": "कृष्ण का जन्म मथुरा में, कंस की जेल में हुआ था।"},
    {"question": "कृष्ण के पिता कौन थे?", "answer": "कृष्ण के पिता वासुदेव थे।"},
    {"question": "कृष्ण की माता कौन थीं?", "answer": "कृष्ण की माता देवकी थीं, और उनका पालन-पोषण यशोदा ने किया।"},
    {"question": "कृष्ण ने किसे गीता सुनाई?", "answer": "कृष्ण ने कुरुक्षेत्र के युद्धक्षेत्र में अर्जुन को भगवद्गीता सुनाई।"},
    {"question": "अर्जुन कौन थे?", "answer": "अर्जुन पांडवों में तीसरे और सर्वश्रेष्ठ धनुर्धर थे। वे इंद्र के पुत्र माने जाते हैं।"},
    {"question": "भीम कौन थे?", "answer": "भीम पांडवों में दूसरे और सबसे शक्तिशाली थे। वे वायु के पुत्र माने जाते हैं।"},
    {"question": "युधिष्ठिर कौन थे?", "answer": "युधिष्ठिर पांडवों के सबसे बड़े भाई और धर्मराज थे। वे सत्य और धर्म के पालक थे।"},
    {"question": "नकुल कौन थे?", "answer": "नकुल पांडवों में चौथे और अश्व विद्या में निपुण थे।"},
    {"question": "सहदेव कौन थे?", "answer": "सहदेव पांडवों में सबसे छोटे और ज्योतिष विद्या में निपुण थे।"},
    {"question": "द्रौपदी कौन थीं?", "answer": "द्रौपदी पाँचों पांडवों की पत्नी थीं। वे राजा द्रुपद की पुत्री थीं और महाभारत की महत्वपूर्ण पात्र हैं।"},
    {"question": "दुर्योधन कौन था?", "answer": "दुर्योधन कौरवों का सबसे बड़ा पुत्र और नेता था। उसकी ईर्ष्या के कारण महाभारत युद्ध हुआ।"},
    {"question": "कर्ण कौन था?", "answer": "कर्ण महान योद्धा और दानवीर था। वह कुंती का पुत्र था लेकिन कौरवों की ओर से लड़ा।"},
    {"question": "भीष्म कौन थे?", "answer": "भीष्म हस्तिनापुर के महान योद्धा और कुरु वंश के पितामह थे। उन्होंने आजीवन ब्रह्मचर्य की प्रतिज्ञा ली थी।"},
    {"question": "द्रोणाचार्य कौन थे?", "answer": "द्रोणाचार्य पांडवों और कौरवों के गुरु थे। वे धनुर्विद्या के महान आचार्य थे।"},
    {"question": "अश्वत्थामा कौन थे?", "answer": "अश्वत्थामा द्रोणाचार्य के पुत्र थे और अमर माने जाते हैं।"},
    {"question": "शकुनि कौन था?", "answer": "शकुनि कौरवों का मामा था। वह चालाक और छली था, उसने ही पासे के खेल में पांडवों को हराने की चाल चली।"},
    {"question": "महाभारत युद्ध कहाँ हुआ?", "answer": "महाभारत का युद्ध कुरुक्षेत्र (आज के हरियाणा) में हुआ।"},
    {"question": "कौरव कितने थे?", "answer": "कौरव 100 भाई थे, जिनमें दुर्योधन सबसे बड़ा था।"},
    {"question": "पांडव कितने थे?", "answer": "पांडव 5 भाई थे — युधिष्ठिर, भीम, अर्जुन, नकुल और सहदेव।"},
    {"question": "गीता क्या है?", "answer": "भगवद्गीता एक पवित्र हिंदू ग्रंथ है जिसमें श्रीकृष्ण ने अर्जुन को जीवन, धर्म, और मोक्ष का उपदेश दिया। इसमें 18 अध्याय और 700 श्लोक हैं।"},
    {"question": "रामायण क्या है?", "answer": "रामायण वाल्मीकि द्वारा रचित महाकाव्य है जिसमें राम के जीवन की कथा है। इसमें 24,000 श्लोक हैं।"},
    {"question": "महाभारत क्या है?", "answer": "महाभारत वेद व्यास द्वारा रचित विश्व का सबसे बड़ा महाकाव्य है। इसमें 1 लाख श्लोक और कौरव-पांडव युद्ध की कथा है।"},
    {"question": "शिव कौन हैं?", "answer": "शिव त्रिमूर्ति के तीसरे देव और संहारकर्ता हैं। वे कैलाश पर्वत पर रहते हैं और उनका वाहन नंदी बैल है।"},
    {"question": "विष्णु कौन हैं?", "answer": "विष्णु त्रिमूर्ति के पालनकर्ता देव हैं। उनके दस अवतार हैं जिनमें राम और कृष्ण प्रमुख हैं।"},
    {"question": "ब्रह्मा कौन हैं?", "answer": "ब्रह्मा त्रिमूर्ति के सृष्टिकर्ता देव हैं। उन्होंने इस संसार की रचना की।"},
    {"question": "लक्ष्मी कौन हैं?", "answer": "लक्ष्मी धन और समृद्धि की देवी हैं। वे विष्णु की पत्नी हैं और दीपावली पर उनकी पूजा होती है।"},
    {"question": "सरस्वती कौन हैं?", "answer": "सरस्वती विद्या, ज्ञान और कला की देवी हैं। वे ब्रह्मा की पत्नी हैं और वसंत पंचमी पर उनकी पूजा होती है।"},
    {"question": "दुर्गा कौन हैं?", "answer": "दुर्गा शक्ति की देवी हैं जिन्होंने महिषासुर का वध किया। नवरात्रि में उनकी पूजा होती है।"},
    {"question": "गणेश कौन हैं?", "answer": "गणेश बुद्धि और विघ्नहर्ता के देवता हैं। वे शिव और पार्वती के पुत्र हैं और हर शुभ काम में सबसे पहले पूजे जाते हैं।"},
    {"question": "इंद्र कौन हैं?", "answer": "इंद्र देवताओं के राजा और वर्षा के देवता हैं।"},
    {"question": "सूर्य कौन हैं?", "answer": "सूर्य प्रकाश और ऊर्जा के देवता हैं। वे कर्ण और सुग्रीव के पिता भी हैं।"},
    {"question": "चंद्र कौन हैं?", "answer": "चंद्र चंद्रमा के देवता हैं जो रात्रि में शीतल प्रकाश देते हैं।"},
    {"question": "यम कौन हैं?", "answer": "यम मृत्यु के देवता हैं जो मृत आत्माओं का न्याय करते हैं।"},
    {"question": "अग्नि कौन हैं?", "answer": "अग्नि अग्नि और यज्ञ के देवता हैं। वे देवताओं और मनुष्यों के बीच दूत का काम करते हैं।"},
    {"question": "वरुण कौन हैं?", "answer": "वरुण जल और समुद्र के देवता हैं।"},
    {"question": "योग क्या है?", "answer": "योग एक प्राचीन भारतीय विद्या है जो शरीर, मन और आत्मा को जोड़ती है। पतंजलि ने इसे 8 अंगों में बताया है।"},
    {"question": "आयुर्वेद क्या है?", "answer": "आयुर्वेद भारत की प्राचीन चिकित्सा पद्धति है। इसमें वात, पित्त और कफ के संतुलन से स्वास्थ्य बनाए रखा जाता है।"},
    {"question": "वेद कितने हैं?", "answer": "वेद चार हैं: ऋग्वेद, सामवेद, यजुर्वेद और अथर्ववेद।"},
    {"question": "रामायण किसने लिखी?", "answer": "रामायण महर्षि वाल्मीकि ने लिखी।"},
    {"question": "महाभारत किसने लिखी?", "answer": "महाभारत वेद व्यास ने लिखी।"},
