    {"question": "अंगद कौन था?", "answer": "अंगद वानर राज बाली का पुत्र था जो राम की सेना में था।"},
    {"question": "बाली कौन था?", "answer": "बाली किष्किंधा का वानर राजा था जिसे राम ने मारा था।"},
    {"question": "उपनिषद क्या हैं?", "answer": "उपनिषद वेदों का अंतिम भाग हैं जिनमें ब्रह्म, आत्मा और जगत के बारे में दार्शनिक विचार हैं। इनकी संख्या 108 मानी जाती है।"},
    {"question": "पुराण कितने हैं?", "answer": "पुराण 18 हैं। इनमें विष्णु पुराण, शिव पुराण, भागवत पुराण आदि प्रमुख हैं।"},
