    {"question": "कर्म क्या है?", "answer": "कर्म का सिद्धांत कहता है कि हमारे कार्यों के अनुसार हमें फल मिलता है। अच्छे कर्म से अच्छा फल और बुरे कर्म से बुरा फल मिलता है।"},
    {"question": "मोक्ष क्या है?", "answer": "मोक्ष जन्म-मृत्यु के चक्र से मुक्ति है। यह हिंदू धर्म का सर्वोच्च लक्ष्य है।"},
    {"question": "अहिंसा क्या है?", "answer": "अहिंसा का अर्थ है किसी भी प्राणी को मन, वचन या कर्म से दुख न देना। यह भारतीय दर्शन का मूल सिद्धांत है।"},
    {"question": "संस्कृत क्या है?", "answer": "संस्कृत भारत की प्राचीनतम भाषा है जिसमें वेद, उपनिषद और अन्य ग्रंथ लिखे गए हैं। इसे देवभाषा भी कहते हैं।"},
    {"question": "नवरात्रि क्या है?", "answer": "नवरात्रि 9 दिनों का त्योहार है जिसमें माँ दुर्गा के 9 रूपों की पूजा होती है।"},
    {"question": "दीपावली क्या है?", "answer": "दीपावली रोशनी का त्योहार है जो राम के अयोध्या वापसी की खुशी में मनाया जाता है।"},
    {"question": "होली क्या है?", "answer": "होली रंगों का त्योहार है जो फाल्गुन मास में मनाया जाता है और बुराई पर अच्छाई की जीत का प्रतीक है।"},
    {"question": "पंचमहाभूत क्या हैं?", "answer": "पंचमहाभूत पाँच तत्व हैं: पृथ्वी, जल, अग्नि, वायु और आकाश। भारतीय दर्शन में इन्हीं से सृष्टि बनी मानी जाती है।"},
    {"question": "अष्टांग योग क्या है?", "answer": "पतंजलि के अनुसार योग के 8 अंग हैं: यम, नियम, आसन, प्राणायाम, प्रत्याहार, धारणा, ध्यान और समाधि।"},
    {"question": "त्रिदोष क्या है?", "answer": "आयुर्वेद में तीन दोष हैं: वात (वायु), पित्त (अग्नि) और कफ (जल+पृथ्वी)। इनके संतुलन से स्वास्थ्य बनता है।"},
    {
        "question": "रामायण के बारे में बताएँ।",
        "answer": "रामायण महर्षि वाल्मीकि द्वारा रचित एक अत्यंत प्राचीन और पवित्र महाकाव्य है, जिसे 'आदिकाव्य' भी कहा जाता है। इसमें कुल 24,000 श्लोक हैं जो सात कांडों—बाल, अयोध्या, अरण्य, किष्किंधा, सुंदर, लंका और उत्तर कांड में विभाजित हैं। यह महाकाव्य भगवान विष्णु के अवतार श्री राम के जीवन की यात्रा है, जिसमें उनके जन्म, सीता से विवाह, 14 वर्ष का वनवास, माता सीता का रावण द्वारा हरण और अंततः धर्म की स्थापना के लिए रावण का वध वर्णित है। रामायण केवल एक कथा नहीं है, बल्कि यह एक आदर्श पुत्र, भाई, पत्नी और राजा के कर्तव्यों का बोध कराने वाला जीवन दर्शन है।"
    },
